// Tiny WebAudio SFX helper for subtle PS1-like UI blips
// Usage: import SFX from './utils/sfx'; SFX.play('hover')

const SFX = (() => {
  let ctx = null;
  let muted = false;
  const last = new Map();

  const ensureCtx = () => {
    if (!ctx) {
      try { ctx = new (window.AudioContext || window.webkitAudioContext)(); } catch {}
    }
    return ctx;
  };

  const throttle = (key, ms) => {
    const now = performance.now();
    const t = last.get(key) || 0;
    if (now - t < ms) return true;
    last.set(key, now);
    return false;
  };

  // Basic blip: one osc with quick AD envelope
  const blip = ({ type = 'triangle', freq = 440, gain = 0.03, dur = 0.08 }) => {
    if (muted) return;
    const ac = ensureCtx();
    if (!ac) return;
    const t0 = ac.currentTime;
    const o = ac.createOscillator();
    const g = ac.createGain();
    o.type = type;
    o.frequency.value = freq;
    g.gain.setValueAtTime(0.0001, t0);
    g.gain.exponentialRampToValueAtTime(gain, t0 + 0.01);
    g.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    o.connect(g).connect(ac.destination);
    o.start(t0);
    o.stop(t0 + dur + 0.02);
  };

  // Two-tone chirp up/down
  const chirp = ({ up = true, base = 360, spread = 160, gain = 0.03, seg = 0.05 }) => {
    if (muted) return;
    const ac = ensureCtx();
    if (!ac) return;
    const t0 = ac.currentTime;
    const o = ac.createOscillator();
    const g = ac.createGain();
    o.type = 'square';
    const f0 = base + (up ? 0 : spread);
    const f1 = base + (up ? spread : 0);
    o.frequency.setValueAtTime(f0, t0);
    o.frequency.linearRampToValueAtTime(f1, t0 + seg);
    g.gain.setValueAtTime(0.0001, t0);
    g.gain.exponentialRampToValueAtTime(gain, t0 + 0.01);
    g.gain.exponentialRampToValueAtTime(0.0001, t0 + seg + 0.04);
    o.connect(g).connect(ac.destination);
    o.start(t0);
    o.stop(t0 + seg + 0.06);
  };

  const api = {
    resume() {
      const ac = ensureCtx();
      if (ac && ac.state === 'suspended') ac.resume().catch(() => {});
    },
    setMuted(v) { muted = !!v; },
    play(kind) {
      switch (kind) {
        case 'hover':
          if (throttle('hover', 100)) return; // avoid spam on mousemove
          blip({ type: 'triangle', freq: 880, gain: 0.02, dur: 0.06 });
          break;
        case 'click':
          if (throttle('click', 80)) return;
          blip({ type: 'square', freq: 440, gain: 0.03, dur: 0.07 });
          break;
        case 'open':
          if (throttle('open', 120)) return;
          chirp({ up: true, base: 320, spread: 160, gain: 0.03, seg: 0.06 });
          break;
        case 'close':
          if (throttle('close', 120)) return;
          chirp({ up: false, base: 320, spread: 160, gain: 0.028, seg: 0.05 });
          break;
        default:
          // noop
          break;
      }
    }
  };

  return api;
})();

export default SFX;
